"""
Secure Advanced Data Filtering Service for MongoDB.

This module provides complex query building WITHOUT using the dangerous
$where operator with user-provided JavaScript. Instead, it translates
a safe filter DSL into native MongoDB query operators.
"""

import re
from typing import Any
from pymongo import MongoClient
from pymongo.collection import Collection


class SecureFilterParser:
    """
    Parses a safe filter expression DSL and converts it to
    native MongoDB query operators (which are indexed and secure).
    
    Supported syntax examples:
        "age > 30"
        "status == 'active' AND score >= 85"
        "name REGEX '^John' AND (age > 25 OR department == 'engineering')"
        "tags CONTAINS 'python'"
        "salary BETWEEN 50000 AND 100000"
        "created_at > '2024-01-01'"
    """

    COMPARISON_OPS = {
        '==': '$eq',
        '!=': '$ne',
        '>': '$gt',
        '>=': '$gte',
        '<': '$lt',
        '<=': '$lte',
    }

    # Whitelist of allowed field names (configurable)
    def __init__(self, allowed_fields: list[str] | None = None):
        self.allowed_fields = allowed_fields

    def _validate_field(self, field: str) -> str:
        """Validate field name to prevent injection via field names."""
        field = field.strip()
        # Only allow alphanumeric, underscores, and dots (for nested fields)
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_.]*$', field):
            raise ValueError(f"Invalid field name: {field!r}")
        # Prevent MongoDB operator injection via field names
        if field.startswith('$'):
            raise ValueError(f"Field names cannot start with '$': {field!r}")
        if self.allowed_fields is not None and field not in self.allowed_fields:
            raise ValueError(
                f"Field {field!r} not in allowed fields: {self.allowed_fields}"
            )
        return field

    def _parse_value(self, value_str: str) -> Any:
        """Safely parse a value string into a Python type."""
        value_str = value_str.strip()

        # String literal
        if (value_str.startswith("'") and value_str.endswith("'")) or \
           (value_str.startswith('"') and value_str.endswith('"')):
            return value_str[1:-1]

        # Boolean
        if value_str.lower() == 'true':
            return True
        if value_str.lower() == 'false':
            return False

        # None/null
        if value_str.lower() in ('null', 'none'):
            return None

        # Integer
        try:
            return int(value_str)
        except ValueError:
            pass

        # Float
        try:
            return float(value_str)
        except ValueError:
            pass

        raise ValueError(f"Cannot parse value: {value_str!r}")

    def _parse_simple_condition(self, condition: str) -> dict:
        """Parse a single condition like 'age > 30'."""
        condition = condition.strip()

        # Handle BETWEEN
        between_match = re.match(
            r'(\S+)\s+BETWEEN\s+(\S+)\s+AND\s+(\S+)',
            condition, re.IGNORECASE
        )
        if between_match:
            field = self._validate_field(between_match.group(1))
            low = self._parse_value(between_match.group(2))
            high = self._parse_value(between_match.group(3))
            return {field: {'$gte': low, '$lte': high}}

        # Handle CONTAINS
        contains_match = re.match(
            r'(\S+)\s+CONTAINS\s+(.+)',
            condition, re.IGNORECASE
        )
        if contains_match:
            field = self._validate_field(contains_match.group(1))
            value = self._parse_value(contains_match.group(2).strip())
            return {field: {'$in': [value]}}

        # Handle IN
        in_match = re.match(
            r'(\S+)\s+IN\s+\[(.+)\]',
            condition, re.IGNORECASE
        )
        if in_match:
            field = self._validate_field(in_match.group(1))
            values = [
                self._parse_value(v.strip())
                for v in in_match.group(2).split(',')
            ]
            return {field: {'$in': values}}

        # Handle REGEX
        regex_match = re.match(
            r"(\S+)\s+REGEX\s+'([^']+)'",
            condition, re.IGNORECASE
        )
        if regex_match:
            field = self._validate_field(regex_match.group(1))
            pattern = regex_match.group(2)
            # Limit regex complexity to prevent ReDoS
            if len(pattern) > 200:
                raise ValueError("Regex pattern too long (max 200 chars)")
            return {field: {'$regex': pattern}}

        # Handle EXISTS
        exists_match = re.match(
            r'(\S+)\s+EXISTS\s+(true|false)',
            condition, re.IGNORECASE
        )
        if exists_match:
            field = self._validate_field(exists_match.group(1))
            exists = exists_match.group(2).lower() == 'true'
            return {field: {'$exists': exists}}

        # Handle standard comparisons: field op value
        for op_str in sorted(self.COMPARISON_OPS.keys(), key=len, reverse=True):
            escaped_op = re.escape(op_str)
            match = re.match(rf'(\S+)\s*{escaped_op}\s*(.+)', condition)
            if match:
                field = self._validate_field(match.group(1))
                value = self._parse_value(match.group(2).strip())
                mongo_op = self.COMPARISON_OPS[op_str]
                if mongo_op == '$eq':
                    return {field: value}
                return {field: {mongo_op: value}}

        raise ValueError(f"Cannot parse condition: {condition!r}")

    def parse(self, expression: str) -> dict:
        """
        Parse a complete filter expression into a MongoDB query.
        Supports AND, OR, and parenthetical grouping.
        """
        if not expression or not expression.strip():
            return {}

        expression = expression.strip()

        # Limit expression length
        if len(expression) > 2000:
            raise ValueError("Filter expression too long (max 2000 chars)")

        return self._parse_expression(expression)

    def _parse_expression(self, expr: str) -> dict:
        """Recursively parse expression with AND/OR and parentheses."""
        expr = expr.strip()

        # Remove outer parentheses if they wrap the entire expression
        if expr.startswith('(') and self._find_matching_paren(expr, 0) == len(expr) - 1:
            expr = expr[1:-1].strip()

        # Split by OR (lowest precedence) at top level
        or_parts = self._split_top_level(expr, ' OR ')
        if len(or_parts) > 1:
            clauses = [self._parse_expression(part) for part in or_parts]
            return {'$or': clauses}

        # Split by AND
        and_parts = self._split_top_level(expr, ' AND ')
        if len(and_parts) > 1:
            clauses = [self._parse_expression(part) for part in and_parts]
            return {'$and': clauses}

        # Base case: simple condition
        return self._parse_simple_condition(expr)

    def _find_matching_paren(self, expr: str, start: int) -> int:
        """Find the matching closing parenthesis."""
        depth = 0
        for i in range(start, len(expr)):
            if expr[i] == '(':
                depth += 1
            elif expr[i] == ')':
                depth -= 1
                if depth == 0:
                    return i
        raise ValueError(f"Unmatched parenthesis in expression: {expr!r}")

    def _split_top_level(self, expr: str, delimiter: str) -> list[str]:
        """Split expression by delimiter, but only at the top level (not inside parens)."""
        parts = []
        depth = 0
        current_start = 0
        i = 0
        delim_upper = delimiter.upper()
        expr_upper = expr.upper()

        while i < len(expr):
            if expr[i] == '(':
                depth += 1
            elif expr[i] == ')':
                depth -= 1
            elif depth == 0 and expr_upper[i:i + len(delimiter)] == delim_upper:
                parts.append(expr[current_start:i].strip())
                i += len(delimiter)
                current_start = i
                continue
            i += 1

        parts.append(expr[current_start:].strip())
        return [p for p in parts if p]


class DataFilteringService:
    """
    Secure advanced data filtering service for MongoDB.
    
    Uses native MongoDB query operators instead of server-side JavaScript.
    This approach is:
      - Secure (no code injection possible)
      - Performant (can use indexes)
      - Auditable (queries are structured data)
    """

    def __init__(
        self,
        connection_string: str = "mongodb://localhost:27017",
        database_name: str = "mydb",
        allowed_fields: list[str] | None = None,
        max_results: int = 1000,
    ):
        self.client = MongoClient(connection_string, serverSelectionTimeoutMS=5000)
        self.db = self.client[database_name]
        self.parser = SecureFilterParser(allowed_fields=allowed_fields)
        self.max_results = max_results

    def query(
        self,
        collection_name: str,
        filter_expression: str,
        projection: dict | None = None,
        sort: list[tuple] | None = None,
        limit: int | None = None,
    ) -> list[dict]:
        """
        Execute a filtered query using a safe expression DSL.
        
        Args:
            collection_name: Name of the MongoDB collection
            filter_expression: Filter in safe DSL format
            projection: Fields to include/exclude
            sort: Sort specification
            limit: Maximum number of results
            
        Returns:
            List of matching documents
        """
        # Validate collection name
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', collection_name):
            raise ValueError(f"Invalid collection name: {collection_name!r}")

        # Parse the filter expression into a safe MongoDB query
        mongo_query = self.parser.parse(filter_expression)

        # Apply query
        collection: Collection = self.db[collection_name]
        cursor = collection.find(mongo_query, projection)

        if sort:
            cursor = cursor.sort(sort)

        effective_limit = min(limit or self.max_results, self.max_results)
        cursor = cursor.limit(effective_limit)

        results = list(cursor)

        # Convert ObjectId to string for JSON serialization
        for doc in results:
            if '_id' in doc:
                doc['_id'] = str(doc['_id'])

        return results

    def explain_query(self, collection_name: str, filter_expression: str) -> dict:
        """Show the MongoDB query that would be generated (for debugging)."""
        mongo_query = self.parser.parse(filter_expression)
        return {
            'filter_expression': filter_expression,
            'mongo_query': mongo_query,
            'collection': collection_name,
        }

    def count(self, collection_name: str, filter_expression: str) -> int:
        """Count documents matching the filter expression."""
        if not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', collection_name):
            raise ValueError(f"Invalid collection name: {collection_name!r}")

        mongo_query = self.parser.parse(filter_expression)
        collection: Collection = self.db[collection_name]
        return collection.count_documents(mongo_query)

    def close(self):
        """Close the MongoDB connection."""
        self.client.close()


